from generating_from_swc import generate_cell
import jaxley as jx


class RGC:
    """
    This class creates a Retinal Ganglion Cell in Jaxley and attaches biophysics.
    """

    def __init__(self):
        self.cell = generate_cell("RGC.swc")

    def get_cell(self):
        return self.cell

    def add_channels(self):
        """
        Add biophysics to the loaded cell to mirror the NEURON implementation
        found in build_in_neuron.py. Section groups are: soma, dend, AH, SOCB, NR, axon.

        Mechanisms and parameters (densities in S/cm^2):
          - Passive (leak): g_pas = 1e-4, e_pas = -64.58
          - Axial and membrane: Ra = 143.2 ohm*cm, cm = 1 uF/cm^2
          - Spiking and Ca mechanisms (approximate mapping to Jaxley):
              Na: gNa = 0.1, E_Na = 60.6 mV
              K:  gK  = 0.05, E_K  = -101.34 mV
              Ca: gCa = 7.5e-4
              KCa: gKCa = 2e-4, E_K = -101.34 mV
              Ca dynamics: depth = 0.1 um, taur = 1.5 ms

        If an exact channel class is not available in this Jaxley version, we try
        sensible fallbacks. Extracellular/xtra are not modeled here.
        """
        cell = self.cell

        # Helper to get a group if present
        def get_group(name):
            try:
                return cell.group(name)
            except Exception:
                # some versions expose groups via a list
                for g in getattr(cell, 'groups', []):
                    if getattr(g, 'name', None) == name:
                        return g
            return None

        # Set passive properties per branch
        for br in getattr(cell, 'branches', []):
            for setter, val in (("set_Ra", 143.2), ("set_cm", 1.0)):
                if hasattr(br, setter):
                    try:
                        getattr(br, setter)(val)
                    except Exception:
                        pass

        # Construct channels with fallbacks based on available API
        leak = None
        for path in (
            ("channels", "Passive", {"g": 1e-4, "e": -64.58}),
            (None, "Passive", {"g": 1e-4, "e": -64.58}),
            ("channels", "Leak", {"g": 1e-4, "e": -64.58}),
            ("channels", "OhmicConductance", {"g": 1e-4, "e": -64.58}),
        ):
            mod, cls, kwargs = path
            try:
                modobj = getattr(jx, mod) if mod else jx
                leak = getattr(modobj, cls)(**kwargs)
                break
            except Exception:
                leak = None
        # Active channels
        ena = 60.6
        ek = -101.34
        na = None
        for path in (
            ("channels", "NaChannel", {"g": 0.1, "e": ena}),
            ("channels", "HHNa", {"g": 0.1, "e": ena}),
            (None, "HHNa", {"g": 0.1, "e": ena}),
            ("channels", "NaV", {"g": 0.1, "e": ena}),
        ):
            try:
                modobj = getattr(jx, path[0]) if path[0] else jx
                na = getattr(modobj, path[1])(**path[2])
                break
            except Exception:
                na = None
        k = None
        for path in (
            ("channels", "KChannel", {"g": 0.05, "e": ek}),
            ("channels", "HHK", {"g": 0.05, "e": ek}),
            (None, "HHK", {"g": 0.05, "e": ek}),
            ("channels", "Kv", {"g": 0.05, "e": ek}),
        ):
            try:
                modobj = getattr(jx, path[0]) if path[0] else jx
                k = getattr(modobj, path[1])(**path[2])
                break
            except Exception:
                k = None
        ca = None
        for path in (
            ("channels", "CaChannel", {"g": 7.5e-4}),
            ("channels", "HVCa", {"g": 7.5e-4}),
            ("channels", "Ca", {"g": 7.5e-4}),
        ):
            try:
                modobj = getattr(jx, path[0]) if path[0] else jx
                ca = getattr(modobj, path[1])(**path[2])
                break
            except Exception:
                ca = None
        kca = None
        for path in (
            ("channels", "KCaChannel", {"g": 2e-4, "e": ek}),
            ("channels", "KCa", {"g": 2e-4, "e": ek}),
        ):
            try:
                modobj = getattr(jx, path[0]) if path[0] else jx
                kca = getattr(modobj, path[1])(**path[2])
                break
            except Exception:
                kca = None
        cad = None
        for path in (
            ("channels", "CaDecay", {"depth": 0.1, "taur": 1.5}),
            ("channels", "CaDyn", {"depth": 0.1, "tau": 1.5}),
        ):
            try:
                modobj = getattr(jx, path[0]) if path[0] else jx
                cad = getattr(modobj, path[1])(**path[2])
                break
            except Exception:
                cad = None

        chan_list = [ch for ch in (leak, na, k, ca, kca, cad) if ch is not None]

        # Attach to each group if present
        for gname in ["soma", "dend", "AH", "SOCB", "NR", "axon"]:
            grp = get_group(gname)
            if grp is None:
                continue
            # Try group-level insert; otherwise fall back to per-branch
            def insert_to(obj, ch):
                for method in ("insert", "add", "attach"):
                    if hasattr(obj, method):
                        try:
                            getattr(obj, method)(ch)
                            return True
                        except Exception:
                            pass
                return False
            for ch in chan_list:
                if not insert_to(grp, ch):
                    for br in getattr(grp, 'branches', []):
                        insert_to(br, ch)
        return self
